{"path": "/tmp/sv-2cc60bf7bc974d978acea0f79c8c2fbf/Components/Pages/Board/BoardSearchBar.razor", "file_text": "<div class="board-search">
    <input type="text" placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await SearchTermChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }
}
"}

