arguments.file_text:
@page "/board"
@rendermode InteractiveServer
@using sv_2cc60bf7bc974d978acea0f79c8c2fbf.Components.Pages.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (isLoading)
{
    <p class="loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="error-message">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats TotalCount="allTasks.Count"
                ToDoCount="todoTasks.Count"
                InProgressCount="inProgressTasks.Count"
                DoneCount="doneTasks.Count"
                OverdueCount="overdueTasks.Count" />

    <BoardSearchBar @bind-SearchTerm="searchTerm" />

    <div class="board-columns">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredTodo"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     OnMoveRight="id => MoveTask(id, \"In Progress\")"
                     OnAddTask="args => AddTask(args, \"To Do\")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     OnMoveLeft="id => MoveTask(id, \"To Do\")"
                     OnMoveRight="id => MoveTask(id, \"Done\")"
                     OnAddTask="args => AddTask(args, \"In Progress\")" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     OnMoveLeft="id => MoveTask(id, \"In Progress\")"
                     OnAddTask="args => AddTask(args, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private string? errorMessage;

    private string searchTerm = string.Empty;

    // Unfiltered column lists (for stats)
    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => allTasks.Where(t => t.DueDate < DateTime.Today).ToList();

    // Filtered column lists (for display)
    private List<TaskItem> filteredTodo => Filter(todoTasks);
    private List<TaskItem> filteredInProgress => Filter(inProgressTasks);
    private List<TaskItem> filteredDone => Filter(doneTasks);

    private List<TaskItem> Filter(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks = allTasks.Select(t => t.Id == taskId ? t with { Status = newStatus } : t).ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) args, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to add task: {ex.Message}";
        }
    }
}

h1 {
    text-align: center;
    margin-bottom: 1rem;
}

/* Stats bar */
.board-stats {
    display: flex;
    gap: 1rem;
    justify-content: center;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat {
    background: #f0f0f0;
    padding: 0.5rem 1rem;
    border-radius: 6px;
    text-align: center;
}

.stat-label {
    display: block;
    font-size: 0.8rem;
    color: #666;
}

.stat-value {
    display: block;
    font-size: 1.4rem;
    font-weight: bold;
}

.stat-overdue .stat-value {
    color: #dc3545;
}

/* Search */
.board-search {
    max-width: 400px;
    margin: 0 auto 1.5rem;
}

.board-search input {
    width: 100%;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 1rem;
}

/* Columns layout */
.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    background: #f7f8fa;
    border-radius: 8px;
    padding: 1rem;
    min-height: 300px;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.column-header h3 {
    margin: 0;
}

.task-count {
    background: #ddd;
    padding: 0.15rem 0.5rem;
    border-radius: 12px;
    font-size: 0.85rem;
    font-weight: bold;
}

/* Task card */
.task-card {
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.5rem;
}

.task-card h4 {
    margin: 0 0 0.25rem;
}

.task-card .assignee {
    margin: 0 0 0.4rem;
    font-size: 0.85rem;
    color: #555;
}

.priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: bold;
    color: #fff;
    margin-right: 0.5rem;
}

.priority-high {
    background: #dc3545;
}

.priority-medium {
    background: #ffc107;
    color: #333;
}

.priority-low {
    background: #28a745;
}

.due-date {
    font-size: 0.8rem;
    color: #888;
}

.card-actions {
    margin-top: 0.5rem;
    display: flex;
    gap: 0.5rem;
}

.btn-move {
    padding: 0.25rem 0.5rem;
    font-size: 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
}

.btn-move:hover {
    background: #e9ecef;
}

/* Add task */
.btn-add-task {
    width: 100%;
    padding: 0.5rem;
    margin-top: 0.5rem;
    border: 2px dashed #ccc;
    border-radius: 6px;
    background: transparent;
    cursor: pointer;
    color: #888;
    font-size: 0.9rem;
}

.btn-add-task:hover {
    border-color: #999;
    color: #555;
}

.add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    margin-top: 0.5rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
}

.add-task-form input,
.add-task-form select {
    padding: 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
}

.btn-save {
    padding: 0.4rem 0.8rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

.btn-cancel {
    padding: 0.4rem 0.8rem;
    background: #6c757d;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

/* States */
.loading {
    text-align: center;
    font-size: 1.2rem;
    color: #666;
}

.error-message {
    text-align: center;
    color: #dc3545;
    padding: 1rem;
}

.error-message button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    border: 1px solid #dc3545;
    background: #fff;
    color: #dc3545;
    border-radius: 4px;
    cursor: pointer;
}

